import { useState } from "react";
import { INITIAL_ROOMS } from "./Data/InitialData";
import { today } from "./Utils/Helper";
import AuthPage from "./Pages/AuthPage";
import AdminDashboard from "./Pages/AdminDashboardPage";
import StudentsPage from "./Pages/StudentsPage";
import RoomsPage from "./Pages/RoomsPage";
import MyRoom from "./Pages/MyRoom";
import AboutPage from "./Pages/AboutPage";
import ContactPage from "./Pages/ContactPage";
import AssignModal from "./Modals/AssignModal";
import Icon from "./components/ui/Icon";
import Btn from "./components/ui/Btn";

function App() {
  const [user, setUser] = useState(null);
  const [students, setStudents] = useState([]);
  const [rooms, setRooms] = useState(INITIAL_ROOMS);
  const [currentPage, setCurrentPage] = useState("dashboard");
  const [showAssignModal, setShowAssignModal] = useState(null);

  const isAdmin = user?.role === "admin";

  const handleAssign = (student, roomId = null) => setShowAssignModal({ student, roomId });

  const confirmAssign = (studentId, roomId) => {
    setStudents(prev => prev.map(s => s.id === studentId ? { ...s, roomId, assignedOn: today() } : s));
    setRooms(prev => prev.map(r => r.id === roomId ? { ...r, occupants: [...r.occupants, studentId] } : r));
    if (user?.id === studentId) setUser(u => ({ ...u, roomId, assignedOn: today() }));
    setShowAssignModal(null);
  };

  const handleVacate = (roomId) => {
    const room = rooms.find(r => r.id === roomId);
    room?.occupants.forEach(studentId => {
      setStudents(prev => prev.map(s => s.id === studentId ? { ...s, roomId: null, assignedOn: null } : s));
    });
    setRooms(prev => prev.map(r => r.id === roomId ? { ...r, occupants: [] } : r));
  };

  const handleRemoveStudent = (studentId) => {
    const student = students.find(s => s.id === studentId);
    if (student?.roomId) {
      setRooms(prev => prev.map(r =>
        r.id === student.roomId ? { ...r, occupants: r.occupants.filter(id => id !== studentId) } : r
      ));
    }
    setStudents(prev => prev.map(s => s.id === studentId ? { ...s, roomId: null, assignedOn: null } : s));
  };

  const navItems = isAdmin
    ? [
        { id: "dashboard", label: "Dashboard", icon: "home" },
        { id: "students", label: "Students", icon: "users" },
        { id: "rooms", label: "Rooms", icon: "bed" },
        { id: "about", label: "About", icon: "info" },
        { id: "contact", label: "Contact", icon: "mail" },
      ]
    : [
        { id: "myroom", label: "My Room", icon: "home" },
        { id: "rooms", label: "Browse Rooms", icon: "bed" },
        { id: "about", label: "About", icon: "info" },
        { id: "contact", label: "Contact", icon: "mail" },
      ];

  if (!user) {
    return <AuthPage onLogin={setUser} students={students} onRegister={s => setStudents(prev => [...prev, s])} />;
  }

  const currentStudent = !isAdmin ? students.find(s => s.id === user.id) || user : null;

  return (
    <div style={{ display: "flex", minHeight: "100vh", background: "#f1f5f9" }}>
      <div style={{ width: 260, background: "#0f172a", color: "#fff", minHeight: "100vh", display: "flex", flexDirection: "column" }}>
        <div style={{ padding: 24, borderBottom: "1px solid #1e293b" }}>
          <h2 style={{ margin: 0, fontSize: 20 }}>HostelHub</h2>
          <p style={{ margin: "5px 0 0", fontSize: 12, color: "#94a3b8" }}>{isAdmin ? "Admin Panel" : "Student Portal"}</p>
        </div>
        <nav style={{ padding: "20px 0", flex: 1 }}>
          {navItems.map(item => (
            <button key={item.id} onClick={() => setCurrentPage(item.id)} style={{
              display: "flex", alignItems: "center", gap: 12, width: "100%", padding: "12px 24px",
              background: currentPage === item.id ? "#1e293b" : "transparent", border: "none",
              color: currentPage === item.id ? "#60a5fa" : "#94a3b8", cursor: "pointer",
              fontSize: 14, fontWeight: 500, textAlign: "left"
            }}> 
              <Icon name={item.icon} size={18} /> {item.label}
            </button>
          ))}
        </nav>
        <div style={{ padding: "20px 24px", borderTop: "1px solid #1e293b" }}>
          <p style={{ margin: "0 0 5px", fontSize: 13, fontWeight: 600 }}>{user.name}</p>
          <p style={{ margin: "0 0 10px", fontSize: 11, color: "#64748b" }}>{user.email}</p>
          <Btn variant="ghost" onClick={() => setUser(null)} style={{ padding: "8px 16px", fontSize: 12 }}>
            <Icon name="logout" size={14} /> Logout
          </Btn>
        </div>
      </div>

      <div style={{ flex: 1, padding: 32 }}>
        {currentPage === "dashboard" && isAdmin && <AdminDashboard rooms={rooms} students={students} />}
        {currentPage === "students" && isAdmin && (
          <StudentsPage students={students} onAssign={handleAssign} onRemove={handleRemoveStudent} />
        )}
        {currentPage === "rooms" && (
          <RoomsPage
            rooms={rooms} isAdmin={isAdmin}
            onAssign={(roomId) => {
              if (isAdmin) { setShowAssignModal({ student: null, roomId }); setCurrentPage("students"); }
              else handleAssign(currentStudent, roomId);
            }}
            onVacate={handleVacate}
            currentStudentId={user?.id}
          />
        )}
        {currentPage === "myroom" && !isAdmin && <MyRoom student={currentStudent} rooms={rooms} />}
        {currentPage === "about" && <AboutPage />}
        {currentPage === "contact" && <ContactPage />}
      </div>

      {showAssignModal && (
        <AssignModal
          student={showAssignModal.student}
          rooms={rooms}
          onConfirm={confirmAssign}
          onClose={() => setShowAssignModal(null)}
        />
      )}
    </div>
  );
}

export default App;
